        // Use a priority queue for Dijkstra-like approach
        PriorityQueue<State> pq = new PriorityQueue<>((a, b) -> Long.compare(b.minCost, a.minCost));

        // Start from node 0
        pq.offer(new State(0, Long.MAX_VALUE, 0));

        while (!pq.isEmpty()) {
            State current = pq.poll();

            // If we reached the destination
            if (current.node == n - 1) {
                return current.minCost;
            }

            // Skip if node is offline
            if (!online[current.node]) {
                continue;
            }

            // Explore neighbors
